void solve(int CASE)
{
	ll ans = 0;

	ll mask1 = (1ll << 7) - 1;
	cout << "? ";
	fa(i, 1, 100) {
		ll tmp = (ll)i << 7;
		cout << (tmp ^ mask1) << ' ';
	}
	cout << endl;
	cout.flush();

	ll x; cin >> x;
	x &= mask1;
	x ^= mask1;
	ans ^= x;

	ll mask2 = ((1ll << 14) - 1) ^ mask1;
	cout << "? ";
	fa(i, 1, 100) {
		ll tmp = (ll)i;
		cout << (tmp ^ mask2) << ' ';
	}
	cout << endl;
	cout.flush();

	cin >> x;
	x &= mask2;
	x ^= mask2;
	ans ^= x;

	cout << "! " << ans << endl;
	cout.flush();
	return;
}
